return [{
  json: {
    type: 'benefit_type_selector',
    message: 'To start your claim, please select your benefit type.',
    benefit_types: [
      { value: 'Optical',       label: 'Optical' },
      { value: 'Outpatient',    label: 'Out Patient' },
      { value: 'Dental',        label: 'Dental' },
      { value: 'Inpatient',     label: 'In Patient' },
      { value: 'Autism',        label: 'Autism' },
      { value: 'ADHD',          label: 'ADHD' },
      { value: 'Physiotherapy', label: 'Physiotherapy' },
      { value: 'Psychotherapy', label: 'Psychotherapy' }
    ],
    resumeUrl: $execution.resumeUrl
  }
}];

const CLAIMS_LOGIC = {
  Optical: {
    mandatory: [
      { type: 'Invoice', description: 'Details of the amount to be paid for services or medications provided to the patient.' },
      { type: 'Payment Proof', description: 'Proof of the required payment completion such as a receipt or bank transfer.' },
      { type: 'Refraction Test Result', description: 'A test that determines the strength of glasses or lenses needed to correct vision.' }
    ],
    optional: []
  },
  Outpatient: {
    mandatory: [
      { type: 'Invoice', description: 'Details of the amount to be paid for services or medications provided to the patient.' },
      { type: 'Receipt', description: 'A document showing the amount paid and the services or medications covered by the payment.' },
      { type: 'Prescription', description: 'A paper written by a doctor that lists the medicines a patient should take and how to use them.' },
      { type: 'Medical Report', description: 'A document that explains a patient\'s health condition, diagnosis, and treatment.' }
    ],
    optional: [
      { type: 'Rad Report', description: 'A radiological report explaining the results of imaging tests such as X-rays or ultrasounds.' },
      { type: 'Lab Result', description: 'A report showing the outcomes of medical tests or laboratory exams.' }
    ]
  },
  Dental: {
    mandatory: [
      { type: 'Medical Report', description: 'A document that explains a patient\'s health condition, diagnosis, and treatment.' },
      { type: 'Payment Proof', description: 'Proof of the required payment completion such as a receipt or bank transfer.' },
      { type: 'Invoice', description: 'Details of the amount to be paid for services or medications provided to the patient.' }
    ],
    optional: []
  },
  Inpatient: {
    mandatory: [
      { type: 'Itemized Invoice', description: 'An invoice that breaks down all services or purchased items with their prices and quantities.' },
      { type: 'Receipt', description: 'A document showing the amount paid and the services or medications covered by the payment.' }
    ],
    optional: [
      { type: 'Rad Report', description: 'A radiological report explaining the results of imaging tests such as X-rays or ultrasounds.' },
      { type: 'Discharge Summary', description: 'A report written when a patient leaves the hospital including health details.' },
      { type: 'Prior Approval', description: 'Permission obtained from the insurance company before the patient receives specific treatment.' },
      { type: 'Operation Note', description: 'An operative note written by the surgeon after a surgical procedure outlining details.' },
      { type: 'Lab Result', description: 'A report showing the outcomes of medical tests or laboratory exams.' }
    ]
  },
  Autism: {
    mandatory: [
      { type: 'Attendance Sheet', description: 'A record of attendance for medical sessions or appointments.' },
      { type: 'Invoice', description: 'Details of the amount to be paid for services or medications provided to the patient.' },
      { type: 'Medical Report', description: 'A document that explains a patient\'s health condition, diagnosis, and treatment.' },
      { type: 'Schedule Of Service', description: 'A list that includes details of each treatment or test session including date and price.' }
    ],
    optional: [
      { type: 'Receipt', description: 'A document showing the amount paid and the services or medications covered by the payment.' },
      { type: 'Prescription', description: 'A paper written by a doctor that lists the medicines a patient should take and how to use them.' }
    ]
  },
  ADHD: {
    mandatory: [
      { type: 'Attendance Sheet', description: 'A record of attendance for medical sessions or appointments.' },
      { type: 'Invoice', description: 'Details of the amount to be paid for services or medications provided to the patient.' },
      { type: 'Medical Report', description: 'A document that explains a patient\'s health condition, diagnosis, and treatment.' },
      { type: 'Schedule Of Service', description: 'A list that includes details of each treatment or test session including date and price.' }
    ],
    optional: [
      { type: 'Receipt', description: 'A document showing the amount paid and the services or medications covered by the payment.' },
      { type: 'Prescription', description: 'A paper written by a doctor that lists the medicines a patient should take and how to use them.' }
    ]
  },
  Physiotherapy: {
    mandatory: [
      { type: 'Attendance Sheet', description: 'A record of attendance for medical sessions or appointments.' },
      { type: 'Invoice', description: 'Details of the amount to be paid for services or medications provided to the patient.' },
      { type: 'Medical Report', description: 'A document that explains a patient\'s health condition, diagnosis, and treatment.' },
      { type: 'Schedule Of Service', description: 'A list that includes details of each treatment or test session including date and price.' }
    ],
    optional: [
      { type: 'Receipt', description: 'A document showing the amount paid and the services or medications covered by the payment.' },
      { type: 'Prescription', description: 'A paper written by a doctor that lists the medicines a patient should take and how to use them.' }
    ]
  },
  Psychotherapy: {
    mandatory: [
      { type: 'Attendance Sheet', description: 'A record of attendance for medical sessions or appointments.' },
      { type: 'Invoice', description: 'Details of the amount to be paid for services or medications provided to the patient.' },
      { type: 'Medical Report', description: 'A document that explains a patient\'s health condition, diagnosis, and treatment.' },
      { type: 'Schedule Of Service', description: 'A list that includes details of each treatment or test session including date and price.' }
    ],
    optional: [
      { type: 'Receipt', description: 'A document showing the amount paid and the services or medications covered by the payment.' },
      { type: 'Prescription', description: 'A paper written by a doctor that lists the medicines a patient should take and how to use them.' }
    ]
  }
};

const body = $json.body || $json;
const benefitType = body.benefit_type || 'Outpatient';
const logic = CLAIMS_LOGIC[benefitType] || CLAIMS_LOGIC['Outpatient'];

const required_docs = [
  ...logic.mandatory.map(doc => ({ key: doc.type, label: doc.type, description: doc.description, required: true })),
  ...logic.optional.map(doc => ({ key: doc.type, label: doc.type, description: doc.description, required: false }))
];

return [{
  json: {
    type: 'document_upload',
    message: `Please upload the required documents for your ${benefitType} claim.`,
    benefit_type: benefitType,
    required_docs,
    resumeUrl: $execution.resumeUrl
  }
}];

const rawOcr = $input.first().json;
const result = Array.isArray(rawOcr) ? rawOcr[0] : rawOcr;

if (!result || result.status !== 'SUCCESS') {
  return [{
    json: {
      type: 'assistant_text',
      message: 'We could not process your documents. Please ensure they are clear and legible, then try again.',
      is_error: true
    }
  }];
}

const exec = result.execution_result;
const val = (field) => (exec[field] && exec[field].value !== undefined) ? exec[field].value : null;

// Retrieve benefit_type stored from Wait — Benefit Type node
let benefitType = null;
try {
  const waitData = $('Wait — Benefit Type').first().json;
  const waitBody = waitData.body || waitData;
  benefitType = waitBody.benefit_type || null;
} catch(e) {
  benefitType = null;
}

const coreFields = ['claimant_name', 'provider_name', 'provider_country', 'service_date', 'claim_amount'];
const nullCount = coreFields.filter(f => val(f) === null).length;

return [{
  json: {
    type: 'extracted_form',
    message: 'We extracted your information. Please review and confirm.',
    extracted_data: {
      claimant_name:    val('claimant_name'),
      policy_number:    val('policy_number'),
      provider_name:    val('provider_name'),
      provider_country: val('provider_country'),
      service_date:     val('service_date'),
      diagnosis_code:   val('diagnosis_code'),
      service_code:     val('service_code'),
      claim_amount:     val('claim_amount'),
      VAT:              val('vat'),
      deductible:       val('deductible'),
      claim_notes:      null,
      benefit_category: benefitType
    },
    ocr_confidence: 0.85,
    is_doc_unclear: nullCount > 2,
    documents_attached: exec.documents_attached || [],
    resumeUrl: $execution.resumeUrl
  }
}];

// STUB — replace with real policy check, geo-validation, and saved IBAN lookup
return [{
  json: {
    type: 'iban_input',
    message: 'Please provide your bank account IBAN for reimbursement.',
    geo_check_status: true,
    is_service_uncovered: false,
    benefit_category: ($('Wait — Benefit Type').first().json.body || $('Wait — Benefit Type').first().json).benefit_type || null,
    saved_ibans: [],
    resumeUrl: $execution.resumeUrl
  }
}];

// STUB — replace with real IBAN verification and financial calculation
const body = $json.body || $json;
return [{
  json: {
    type: 'financial_summary',
    iban_verified: true,
    estimated_payout: 0.00,
    processing_type: 'Standard',
    currency: 'SAR',
    claim_amount: 0.00,
    VAT: 0.00,
    deductible: 0.00,
    resumeUrl: $execution.resumeUrl
  }
}];

// STUB — replace with real claim submission to MG Core
const claimId = 'UCRN' + Date.now();
return [{
  json: {
    type: 'success_card',
    claim_id: claimId,
    submission_timestamp: new Date().toISOString(),
    processing_type: 'Standard',
    message: 'Your claim has been submitted successfully. You will receive updates in your notification centre.'
  }
}];
